1	import { quote } from "./claim-office.js";
2	
3	export function runScenario(scenario: any): { results: unknown[] } {
4	  const results: unknown[] = [];
5	  for (const step of scenario.steps) {
6	    if (step.op === "quote") {
7	      const premium = quote({
8	        customer: {
9	          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
10	          previousContracts: results.length,
11	        },
12	        items: step.items,
13	      });
14	      results.push({ premium });
15	    }
16	  }
17	  return { results };
18	}
19

1	export interface QuoteInput {
2	  customer?: { yearsWithMHPCO: number; previousContracts?: number };
3	  items: {
4	    type: string;
5	    material?: string;
6	    cursed?: boolean;
7	    enchantment?: number;
8	  }[];
9	}
10	
11	const PROCESSING_FEE = 5;
12	
13	const BLOCK_SIZE = 3;
14	const BLOCK_PRICE = 60;
15	
16	const CURSE_SURCHARGE_RATE = 0.5;
17	
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
20	
21	const LOYALTY_MINIMUM_YEARS = 2;
22	const LOYALTY_DISCOUNT_RATE = 0.2;
23	
24	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
25	
26	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
27	
28	// Premiums are rounded up to whole G, in MHPCO's favour.
29	const roundUpToWholeG = (amount: number): number => Math.ceil(amount);
30	
31	// Payouts are rounded down to whole G, in MHPCO's favour.
32	const roundDownToWholeG = (amount: number): number => Math.floor(amount);
33	
34	const BASE_PREMIUMS: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: 25,
40	  moonstone: 25,
41	};
42	
43	export function quote(input: QuoteInput): number {
44	  const countsByType: Record<string, number> = {};
45	  for (const item of input.items) {
46	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
47	  }
48	
49	  let basePremiumTotal = 0;
50	  for (const type of Object.keys(countsByType)) {
51	    const count = countsByType[type];
52	    if (count === BLOCK_SIZE) {
53	      basePremiumTotal += BLOCK_PRICE;
54	    } else {
55	      basePremiumTotal += count * BASE_PREMIUMS[type];
56	    }
57	  }
58	
59	  const isFirstInsurance = input.customer?.previousContracts !== undefined;
60	
61	  let surchargeTotal = 0;
62	  for (const item of input.items) {
63	    const itemBasePremium = BASE_PREMIUMS[item.type];
64	    if (item.cursed) {
65	      surchargeTotal += itemBasePremium * CURSE_SURCHARGE_RATE;
66	    }
67	    if (
68	      item.enchantment !== undefined &&
69	      item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
70	    ) {
71	      surchargeTotal += itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
72	    }
73	    if (isFirstInsurance) {
74	      surchargeTotal += itemBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
75	    }
76	  }
77	
78	  const isLoyal =
79	    (input.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_MINIMUM_YEARS;
80	  const isFollowUp = (input.customer?.previousContracts ?? 0) >= 1;
81	
82	  const loyaltyDiscount = isLoyal ? basePremiumTotal * LOYALTY_DISCOUNT_RATE : 0;
83	  const followUpDiscount = isFollowUp
84	    ? basePremiumTotal * FOLLOW_UP_DISCOUNT_RATE
85	    : 0;
86	
87	  const rawPremium =
88	    basePremiumTotal -
89	    loyaltyDiscount -
90	    followUpDiscount +
91	    surchargeTotal +
92	    PROCESSING_FEE;
93	
94	  return roundUpToWholeG(rawPremium);
95	}
96	
97	export interface ClaimInput {
98	  items: { type: string; material?: string; enchantment?: number }[];
99	  remainingCap?: number;
100	  incident: { cause: string; damages: { itemType: string; amount: number }[] };
101	}
102	
103	export interface ClaimResult {
104	  payout: number;
105	  // The cap left over after this claim, so successive claims can be chained by
106	  // passing it back in as ClaimInput.remainingCap. Optional because callers who
107	  // only need the payout can ignore it.
108	  remainingCap?: number;
109	}
110	
111	const DEDUCTIBLE = 100;
112	
113	const INSURANCE_VALUES: Record<string, number> = {
114	  sword: 1000,
115	  amulet: 600,
116	  staff: 800,
117	  potion: 400,
118	  rune: 250,
119	  moonstone: 250,
120	};
121	
122	const CAP_MULTIPLIER = 2;
123	
124	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
125	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
126	
127	const hasHighEnchantment = (
128	  item: ClaimInput["items"][number] | undefined,
129	): boolean =>
130	  item?.enchantment !== undefined &&
131	  item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
132	
133	// Reimbursement for a single damage, before the deductible is applied.
134	const reimbursementBeforeDeductible = (
135	  item: ClaimInput["items"][number] | undefined,
136	  damageAmount: number,
137	): number =>
138	  hasHighEnchantment(item)
139	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
140	    : damageAmount;
141	
142	// The total payout is capped at a multiple of the unmodified insurance sum.
143	const payoutCap = (items: ClaimInput["items"]): number => {
144	  const insuranceSum = items.reduce(
145	    (total, item) => total + INSURANCE_VALUES[item.type],
146	    0,
147	  );
148	  return CAP_MULTIPLIER * insuranceSum;
149	};
150	
151	export function claim(input: ClaimInput): ClaimResult {
152	  const rawPayout = input.incident.damages.reduce((total, damage) => {
153	    const item = input.items.find((i) => i.type === damage.itemType);
154	    const reimbursed = reimbursementBeforeDeductible(item, damage.amount);
155	    return total + (reimbursed - DEDUCTIBLE);
156	  }, 0);
157	
158	  const availableRemainingCap = input.remainingCap ?? payoutCap(input.items);
159	  const payout = roundDownToWholeG(Math.min(rawPayout, availableRemainingCap));
160	  return { payout, remainingCap: availableRemainingCap - payout };
161	}
